import React, { createContext, useContext, useState, useEffect, useRef, ReactNode } from 'react';
import { User } from './AuthContext';


export interface Product {
  id: number;
  title: string;
  description: string;
  sellerId: number;
  expertId: number | null;
  categoryId: number | null;
  status: 'PENDING' | 'UNDER_REVIEW' | 'APPROVED' | 'REJECTED' | 'LIVE';
  rejectionReason?: string;
  suggestedPrice?: number;
  images: string[];
  submittedAt: string;
  artist?: string;
  documents?: string[];
}

export interface Appointment {
  id: number;
  productId: number;
  expertId: number;
  sellerId: number;
  date: string;
  location: string;
  status: 'SCHEDULED' | 'COMPLETED' | 'CANCELLED';
  notes: string;
}

export interface ChatMessage {
  id: number;
  productId: number;
  fromId: number;
  toId: number;
  text: string;
  time: string;
  documents?: string[];
}

export interface EvalRequest {
  id: number;
  productId: number;
  sellerId: number;
  message: string;
  documents: string[];
  sentAt: string;
  status: 'pending' | 'accepted' | 'rejected';
  acceptedByExpertId?: number;
}

export interface Bid {
  id: number;
  auctionId: number;
  bidder: string;
  amount: number;
  time: string;
}

export interface Auction {
  id: number;
  productId?: number;
  title: string;
  artist: string;
  category: string;
  image: string;
  currentBid: number;
  startingBid: number;
  endsAt: string;
  status: 'active' | 'upcoming' | 'sold';
  bidsCount: number;
  winnerName?: string;
  year?: number;
  medium?: string;
  dimensions?: string;
  condition?: string;
  provenance?: string;
}

export interface DataContextType {
  users: User[];
  products: Product[];
  appointments: Appointment[];
  messages: ChatMessage[];
  auctions: Auction[];
  bids: Bid[];
  addUser: (u: User) => void;
  updateUserRole: (id: number, role: User['role']) => void;
  updateProduct: (p: Product) => void;
  addAppointment: (a: Appointment) => void;
  addMessage: (m: ChatMessage) => void;
  getChatForProduct: (prodId: number) => ChatMessage[];
  placeBid: (auctionId: number, bidder: string, amount: number) => void;
  getBidsForAuction: (auctionId: number) => Bid[];
  updateAuctionStatus: (auctionId: number, status: Auction['status']) => void;
  purchasedIds: number[];
  markAsPurchased: (id: number) => void;
  setUsers: React.Dispatch<React.SetStateAction<User[]>>;
  setAuctions: React.Dispatch<React.SetStateAction<Auction[]>>;
  evalRequests: EvalRequest[];
  addEvalRequest: (r: EvalRequest) => void;
  updateEvalRequest: (r: EvalRequest) => void;
  addProduct: (p: Product) => void;
}

